}

// ---------------------------------------------------------------------------
// splitForTelegram
// ---------------------------------------------------------------------------
export function splitForTelegram(text: string, max = TG_MAX): string[] {
  if (text.length <= max) return [text];
  const raw: string[] = [];
  let rest = text;
  while (rest.length > max) {
    let cut = rest.lastIndexOf("\n\n", max);
    if (cut < max * 0.5) cut = rest.lastIndexOf("\n", max);
    if (cut < max * 0.5) cut = rest.lastIndexOf(" ", max);
    if (cut <= 0) cut = max;
    raw.push(rest.slice(0, cut));
    rest = rest.slice(cut).replace(/^[\n ]+/, "");
  }
  if (rest.length) raw.push(rest);

  const fenceRe = /^```([^\n`]*)\s*$/;
  const out: string[] = [];
  let openLang = "";
  for (let i = 0; i < raw.length; i++) {
    let piece = raw[i];
    if (openLang !== "") {
      piece = "```" + openLang + "\n" + piece;
    }
    const lines = piece.split("\n");
    let inside = false;
    let lang = "";
    for (const line of lines) {
      const m = line.match(fenceRe);
      if (!m) continue;
      if (!inside) {
        inside = true;
        lang = m[1] ?? "";
      } else {
        inside = false;
        lang = "";
      }
    }
    if (inside && i < raw.length - 1) {
      piece = piece + (piece.endsWith("\n") ? "" : "\n") + "```";
      openLang = lang;
    } else {
      openLang = "";
    }
    out.push(piece);
  }
  return out;
}

// ---------------------------------------------------------------------------
// renderReply (streaming display)
// ---------------------------------------------------------------------------
export interface RenderResult {
  content: string;
  parseMode: "HTML" | undefined;
}

export function renderReply(
  session: ChatSession,
  done: boolean,
  parsers: ScheduleParsers,
): RenderResult {
  const toolLines = toolPrefixLines(session);
  const tools = toolLines.length ? toolLines.join("\n") + "\n\n" : "";
  const cursor = done ? "" : " ▍";
  const emptyFallback = () => {
    if (!done) return session.thinkingBuffer ? "" : "Thinking…";
    const n = session.toolTimeline.length;
    return n > 0 ? `(no text yet — ${n} tool call${n === 1 ? "" : "s"} so far)` : "(no response)";
  };

  // Show thinking progress during streaming (hide when done)
  let thinkingBlock = "";
  if (!done && session.thinkingBuffer) {
    // Show last ~200 chars of thinking as blockquote
    const t = session.thinkingBuffer;
    const preview = t.length > 200 ? "…" + t.slice(-200) : t;
    thinkingBlock = "💭 " + preview.split("\n").join("\n> ") + "\n\n";
  }

  const raw = session.buffer || emptyFallback();
  const stripped = transformReplyTokens(raw, parsers).text;
  let body = stripped || emptyFallback();
  // 扣除 tools/thinkingBlock/cursor 佔用的長度，避免拼接後超過 Telegram 4096 上限
  const overhead = tools.length + thinkingBlock.length + cursor.length;
  const bodyBudget = Math.max(TG_MAX - overhead, 200);
  if (body.length > bodyBudget) {
    body = "…" + body.slice(-bodyBudget);
  }

  const plain = tools + thinkingBlock + body + cursor;
  const { html } = markdownToHtml(plain);
  // HTML 膨脹超過 Telegram 4096 上限時 fallback 到純文字（markdown budget 已 ≤3900，純文字必定安全）
  if (html.length > 4096) {
    return { content: plain, parseMode: undefined };
  }
  return { content: html, parseMode: "HTML" };
}

// ---------------------------------------------------------------------------
// renderDraftReply (draft streaming display)
// ---------------------------------------------------------------------------
// Telegram client 對 draft 更新的動畫是「長度差」語意：立即顯示新文字的前
// strlen(prev) 個字元，再淡入最後 max(0, strlen(new) - strlen(prev)) 個 —
// 隱含假設內容 append-only。若在頭部插入（新 tool 行完成），client 先顯示
// 的前綴會少掉 body 尾端同長度的字元、再慢慢淡回，使用者看到已顯示的文字
// 倒退。所以 draft 幀把 volatile 區（thinking/tools）放在 body 之後，讓每
// 幀盡量只在尾端追加。
// 輸出 markdown 原文：sendRichMessageDraft 的 rich_message.markdown 收
// markdown（final 持久化的 trySendRichMessage 也是傳 markdown），不可餵
// renderReply 的 HTML。
export function renderDraftReply(
  session: ChatSession,
  parsers: ScheduleParsers,
): string {
  const raw = session.buffer || "";
  const stripped = transformReplyTokens(raw, parsers).text;

  let thinkingBlock = "";
  if (session.thinkingBuffer) {
    const t = session.thinkingBuffer;
    const preview = t.length > 200 ? "…" + t.slice(-200) : t;
    thinkingBlock = "💭 " + preview.split("\n").join("\n> ");
  }
  const toolLines = toolPrefixLines(session);
  const tools = toolLines.length ? toolLines.join("\n") : "";

  const statusTail = [thinkingBlock, tools].filter(Boolean).join("\n\n");
  const cursor = " ▍";
  const overhead = (statusTail ? statusTail.length + 2 : 0) + cursor.length;
  const bodyBudget = Math.max(TG_MAX - overhead, 200);
  let body = stripped;
  if (body.length > bodyBudget) {
    body = "…" + body.slice(-bodyBudget);
  }
  const head = body ? body + cursor : "";
  // 全空 → 回空字串，trySendDraft 會送 text=undefined，server 顯示原生 "Thinking…"
  return [head, statusTail].filter(Boolean).join("\n\n");
}

