/** One tool call's progress within the in-flight turn. */
export interface ToolEvent {
  /** ACP toolCallId when present, else a synthetic id for matching updates. */
  id: string;
  /** Human-readable tool name/title. */
  name: string;
  status: "running" | "completed" | "failed";
  /** Date.now() at tool_call start. */
  startedAt: number;
  /** Wall-clock ms once completed/failed; undefined while running. */
  elapsedMs?: number;
}

const TOOL_STATUS_EMOJI = {
  running: "⚙️",
  completed: "✅",
  failed: "❌",
} as const;

/**
 * Mark a running tool as completed/failed, stamping elapsed time. Matches by
 * ACP toolCallId; if the update carries no id (or none matches), falls back to
 * the most recent still-running entry so the line still transitions.
 */
function markToolDone(
  session: ChatSession,
  updId: string | undefined,
  status: "completed" | "failed",
): void {
  let entry = updId
    ? session.toolTimeline.find((t) => t.id === updId && t.status === "running")
    : undefined;
  if (!entry) {
    for (let i = session.toolTimeline.length - 1; i >= 0; i--) {
      if (session.toolTimeline[i].status === "running") {
        entry = session.toolTimeline[i];
        break;
      }
    }
  }
  if (entry) {
    entry.status = status;
    entry.elapsedMs = Date.now() - entry.startedAt;
  }
}

/**
 * Lines shown as the tool-progress prefix of the streamed reply: one line per
 * tool (latest 5) as `<emoji> <name> (<secs>s)`, followed by any advisory
 * lines (reflexion hints) carried in {@link ChatSession.toolLog}.
 */
// Tool 行是進度指示器不是審計記錄：title 是 adapter 原文（可能是整條
// Bash 命令或絕對路徑，甚至含換行），render 層單行化 + 截斷；
// toolTimeline 保留原始資料不加工。
const TOOL_LINE_NAME_MAX = 64;

export function toolPrefixLines(session: ChatSession): string[] {
  const lines = session.toolTimeline.slice(-5).map((t) => {
    const secs =
      t.status !== "running" && t.elapsedMs !== undefined
        ? ` (${(t.elapsedMs / 1000).toFixed(1)}s)`
        : "";
    let name = t.name.replace(/\s*[\r\n]+\s*/g, " ");
    if (name.length > TOOL_LINE_NAME_MAX) {
      name = name.slice(0, TOOL_LINE_NAME_MAX - 1) + "…";
    }
    return `${TOOL_STATUS_EMOJI[t.status]} ${name}${secs}`;
  });
  return [...lines, ...session.toolLog];
}

/**
 * Per-Telegram-chat session. Each chat owns its own Kiro ACP subprocess,
 * so conversations stay isolated.
 */
export interface ChatSession {
  chatId: number;
  userId?: number;
  client: Provider;
  /** Which provider type is active for this session. */

