node -e "
const { renderDraftReply, renderReply } = require('./dist/telegram-ui.js');
const parsers = { parseDuration: () => null, parseAbsoluteTime: () => null, parseRecurrence: () => null, computeNextRunAt: () => null };
const mkSession = (buffer, tools) => ({ buffer, thinkingBuffer: '', toolTimeline: tools || [], toolLog: [] });

// 1. draft 全空 + header → 回 header 本身
let s = mkSession('');
let out = renderDraftReply(s, parsers, '我選擇了：方案A');
console.log('1.', out === '我選擇了：方案A' ? 'OK' : 'FAIL: ' + JSON.stringify(out));

// 2. draft 有 body + header → header 在最前
s = mkSession('hello world');
out = renderDraftReply(s, parsers, '我選擇了：方案A');
console.log('2.', out.startsWith('我選擇了：方案A\n\nhello world') ? 'OK' : 'FAIL: ' + JSON.stringify(out));

// 3. draft 無 header → 行為不變（全空回空字串）
s = mkSession('');
out = renderDraftReply(s, parsers);
console.log('3.', out === '' ? 'OK' : 'FAIL: ' + JSON.stringify(out));

// 4. renderReply + header → plain/html 都含 header 前綴
s = mkSession('hello');
let r = renderReply(s, false, parsers, '我選擇了：方案A');
console.log('4.', r.content.includes('我選擇了：方案A') && r.content.indexOf('我選擇了') === 0 ? 'OK' : 'FAIL: ' + JSON.stringify(r));

// 5. renderReply 超長 body + header → 總長不超過 4096
s = mkSession('x'.repeat(6000));
r = renderReply(s, false, parsers, '我選擇了：' + 'y'.repeat(50));
console.log('5.', r.content.length <= 4096 && r.content.startsWith('我選擇了：') ? 'OK' : 'FAIL len=' + r.content.length);

// 6. header 恆定 → 前綴不變（append-only 保持）
s = mkSession('abc', [{ id: 't1', name: 'Read foo.ts', status: 'running', startedAt: Date.now() }]);
const f1 = renderDraftReply(s, parsers, 'H');
s.buffer = 'abcdef';
const f2 = renderDraftReply(s, parsers, 'H');
console.log('6.', f2.startsWith('H\n\nabc') && f1.startsWith('H\n\nabc') ? 'OK' : 'FAIL');
"

