private applyUpdate(session: ChatSession, u: SessionUpdate) {
  this.resetInactivityTimer(session);
  const up = u.update;
  // Opportunistically capture usage-like meta the agent may attach.
  const meta = (up as { _meta?: Record<string, unknown> })._meta;
  const usage =
    (meta?.usage as Record<string, unknown> | undefined) ??
    ((up as { usage?: Record<string, unknown> }).usage);

