// Tool 行是進度指示器不是審計記錄：title 是 adapter 原文（可能是整條
// Bash 命令或絕對路徑，甚至含換行），render 層單行化 + 截斷；
// toolTimeline 保留原始資料不加工。
const TOOL_LINE_NAME_MAX = 64;

export function toolPrefixLines(session: ChatSession): string[] {
  const lines = session.toolTimeline.slice(-5).map((t) => {
    const secs =
      t.status !== "running" && t.elapsedMs !== undefined
        ? ` (${(t.elapsedMs / 1000).toFixed(1)}s)`
        : "";
    let name = t.name.replace(/\s*[\r\n]+\s*/g, " ");
    if (name.length > TOOL_LINE_NAME_MAX) {
      name = name.slice(0, TOOL_LINE_NAME_MAX - 1) + "…";
    }
    return `${TOOL_STATUS_EMOJI[t.status]} ${name}${secs}`;
  });
  return [...lines, ...session.toolLog];
}

