process.chdir("G:/AI/telegram-kiro-bridge-main");
const { SessionManager, toolPrefixLines } = await import("file:///G:/AI/telegram-kiro-bridge-main/dist/sessionManager.js");

const sm = new SessionManager();
const mkSession = () => ({
  chatId: 1, buffer: "", thinkingBuffer: "", toolTimeline: [], toolLog: [],
  charsOut: 0, activeProvider: "direct", inflight: true, history: [],
});

let pass = 0, fail = 0;
const check = (name, cond) => { cond ? pass++ : fail++; console.log(cond ? "OK " : "FAIL", name); };

// 1. in_progress update 帶完整 title → timeline entry.name 回寫 + onUpdate 觸發
let s = mkSession();
let updates = 0;
s.onUpdate = () => updates++;
sm.applyUpdate(s, { update: { sessionUpdate: "tool_call", toolCallId: "t1", title: "Bash" } });
sm.applyUpdate(s, { update: { sessionUpdate: "tool_call_update", toolCallId: "t1", status: "in_progress", title: "Bash: npx tsc -p ." } });
check("in_progress title 回寫 entry.name", s.toolTimeline[0].name === "Bash: npx tsc -p .");
check("title 變更觸發 onUpdate（tool_call 1 + update 1 = 2）", updates === 2);

// 2. 相同 title 的 in_progress 不觸發多餘 onUpdate
sm.applyUpdate(s, { update: { sessionUpdate: "tool_call_update", toolCallId: "t1", status: "in_progress", title: "Bash: npx tsc -p ." } });
check("title 未變不觸發 onUpdate", updates === 2);

// 3. completed update 帶 title → log 名用完整名，entry 也回寫
let s2 = mkSession();
sm.applyUpdate(s2, { update: { sessionUpdate: "tool_call", toolCallId: "t2", title: "tool" } });
sm.applyUpdate(s2, { update: { sessionUpdate: "tool_call_update", toolCallId: "t2", status: "completed", title: "Read foo.ts" } });
check("completed 帶 title 回寫 entry.name", s2.toolTimeline[0].name === "Read foo.ts");
check("completed 狀態轉換", s2.toolTimeline[0].status === "completed");

// 4. update 無 toolCallId → fallback 最近 running entry
let s3 = mkSession();
sm.applyUpdate(s3, { update: { sessionUpdate: "tool_call", toolCallId: "a", title: "Grep old" } });
sm.applyUpdate(s3, { update: { sessionUpdate: "tool_call_update", toolCallId: "a", status: "completed" } });
sm.applyUpdate(s3, { update: { sessionUpdate: "tool_call", toolCallId: "b", title: "partial" } });
sm.applyUpdate(s3, { update: { sessionUpdate: "tool_call_update", status: "in_progress", title: "Write bar.ts full" } });
check("無 id fallback 最近 running（不動已完成的）", s3.toolTimeline[0].name === "Grep old" && s3.toolTimeline[1].name === "Write bar.ts full");

// 5. update 無 title → 原名保留（不退化成 undefined/"tool"）
let s4 = mkSession();
sm.applyUpdate(s4, { update: { sessionUpdate: "tool_call", toolCallId: "c", title: "Edit baz.ts" } });
sm.applyUpdate(s4, { update: { sessionUpdate: "tool_call_update", toolCallId: "c", status: "in_progress" } });
check("無 title 的 update 保留原名", s4.toolTimeline[0].name === "Edit baz.ts");

// 6. render 層拿到完整名
check("toolPrefixLines 顯示完整名", toolPrefixLines(s)[0].includes("Bash: npx tsc -p ."));

console.log(`\n${pass}/${pass + fail} passed`);
process.exit(fail ? 1 : 0);

