// ─── 1. Draft 幀純淨：不含 thinking/tools（volatile 區走 status 訊息） ───

{
  const s = makeSession({
    buffer: "目前在驗證streaming",
    thinking: "Let me check the onChange callback.",
    tools: [tool("Read File", 2700), tool("Read File", 2600)],
  });
  const frame = renderDraftReply(s, parsers);
  assert("body 在最前面", frame.indexOf("目前在驗證streaming") === 0, frame);
  assert("draft 幀不含 thinking", !frame.includes("💭"), frame);
  assert("draft 幀不含 tool 行", !frame.includes("✅"), frame);
}

// ─── 2. Tools/thinking 變動完全不影響 draft 幀（append-only 根治重點） ───

{
  const base = { buffer: "目前在驗證streaming" };
  const frame1 = renderDraftReply(
    makeSession({ ...base, tools: [tool("Read File", 2700)] }),
    parsers,
  );
  const frame2 = renderDraftReply(
    makeSession({
      ...base,
      thinking: "new thought",
      tools: [tool("Read File", 2700), tool("Terminal", 8100)],
    }),
    parsers,
  );
  assert("tools/thinking 變動後 draft 幀逐字相同", frame1 === frame2, frame2);
}

// ─── 2b. Status 訊息：tool 種類行 + thinking preview ───

{
  const s = makeSession({
    thinking: "Let me check the onChange callback.",
    tools: [tool("Read File", 2700), { name: "Terminal cmd", status: "running", startedAt: Date.now() }],
  });
  const status = renderStatusMessage(s);
  // 顯示層只取 title 第一個詞（工具種類），"Read File" → "Read"
  assert("status 含完成 tool 行", status.includes("✅ Read (2.7s)"), status);
  assert("status 含 running tool 行", status.includes("⚙️ Terminal"), status);
  assert("status tool 行不帶參數", !status.includes("Read File") && !status.includes("Terminal cmd"), status);
  assert("status 含 thinking preview", status.includes("💭"), status);
  assert("全空 status 回空字串", renderStatusMessage(makeSession()) === "");
}

// ─── 2c. replyHeader：恆定前綴，全空幀也顯示 ───

{
  const withBody = renderDraftReply(makeSession({ buffer: "hello" }), parsers, "我選擇了：方案A");
  assert("header 在 body 前", withBody.startsWith("我選擇了：方案A\n\nhello"), withBody);
  const emptyFrame = renderDraftReply(makeSession(), parsers, "我選擇了：方案A");
  assert("全空幀回 header 本身", emptyFrame === "我選擇了：方案A", emptyFrame);
}

